import{_ as l,c as t,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"快速上手：安装配置启动 Gateway 并发送第一条消息与了解 DM 配对保护 | Clawdbot 教程","description":"本章节引导你完成 Clawdbot 的首次使用，包括安装、配置、启动 Gateway、发送第一条消息以及了解 DM 配对保护机制。","frontmatter":{"title":"快速上手：安装配置启动 Gateway 并发送第一条消息与了解 DM 配对保护 | Clawdbot 教程","sidebarTitle":"从零开始使用","subtitle":"快速上手：从安装到第一条消息","description":"本章节引导你完成 Clawdbot 的首次使用，包括安装、配置、启动 Gateway、发送第一条消息以及了解 DM 配对保护机制。","tags":["入门","快速开始"],"prerequisite":[],"order":10},"headers":[],"relativePath":"zh/moltbot/moltbot/start/index.md","filePath":"zh/moltbot/moltbot/start/index.md"}'),e={name:"zh/moltbot/moltbot/start/index.md"};function r(n,a,o,p,h,g){return i(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="快速上手-从安装到第一条消息" tabindex="-1">快速上手：从安装到第一条消息 <a class="header-anchor" href="#快速上手-从安装到第一条消息" aria-label="Permalink to &quot;快速上手：从安装到第一条消息&quot;">​</a></h1><p>欢迎使用 Clawdbot！本章节将引导你完成从零开始使用 Clawdbot 的完整流程。无论你是想快速体验 AI 助手，还是深入了解配置选项，这里都有对应的教程。</p><hr><h2 id="章节概述" tabindex="-1">章节概述 <a class="header-anchor" href="#章节概述" aria-label="Permalink to &quot;章节概述&quot;">​</a></h2><p>本章节包含 5 个教程，覆盖了 Clawdbot 的完整上手流程：从安装软件、配置 AI 模型和通信渠道，到启动 Gateway 守护进程、发送第一条消息，最后了解默认的安全保护机制。完成本章节后，你将拥有一个可以正常使用的个人 AI 助手。</p><hr><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to &quot;学习路径建议&quot;">​</a></h2><p>我们推荐按照以下顺序学习这些教程：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[getting-started&lt;br&gt;快速开始] --&gt; B[onboarding-wizard&lt;br&gt;向导式配置]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[gateway-startup&lt;br&gt;启动 Gateway]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[first-message&lt;br&gt;发送第一条消息]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[pairing-approval&lt;br&gt;DM 配对与访问控制]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#3b82f6,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#10b981,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#f59e0b,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#8b5cf6,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#ef4444,color:#fff</span></span></code></pre></div><p><strong>学习顺序说明</strong>：</p><ol><li><strong>快速开始</strong>（必须）：完成基础安装和配置，这是所有后续学习的前提</li><li><strong>向导式配置</strong>（推荐）：深入了解向导的各个选项，适合想要精细配置的用户</li><li><strong>启动 Gateway</strong>（必须）：了解如何启动和管理 Gateway 守护进程</li><li><strong>发送第一条消息</strong>（必须）：验证配置是否正确，开始使用 AI 助手</li><li><strong>DM 配对与访问控制</strong>（推荐）：了解默认的安全机制，保护你的 AI 助手</li></ol><div class="tip custom-block"><p class="custom-block-title">快速通道</p><p>如果你只想快速体验，可以只学习「快速开始」和「启动 Gateway」两个教程，然后直接发送消息。其他教程可以后续按需学习。</p></div><hr><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><p>在学习本章节之前，请确保：</p><ul><li><strong>Node.js</strong>：≥ 22.12.0（使用 <code>node -v</code> 检查）</li><li><strong>操作系统</strong>：macOS / Linux / Windows (WSL2)</li><li><strong>包管理器</strong>：npm / pnpm / bun</li><li><strong>AI 模型账户</strong>（推荐）： <ul><li>Anthropic Claude 账户（Pro/Max 订阅），支持 OAuth 流程</li><li>或准备好 OpenAI / DeepSeek / OpenRouter 等提供商的 API Key</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">Windows 用户请注意</p><p>Windows 上强烈推荐使用 <strong>WSL2</strong>，因为：</p><ul><li>许多渠道依赖本地二进制文件</li><li>守护进程（launchd/systemd）在 Windows 上不可用</li></ul></div><hr><h2 id="子页面导航" tabindex="-1">子页面导航 <a class="header-anchor" href="#子页面导航" aria-label="Permalink to &quot;子页面导航&quot;">​</a></h2><h3 id="_1-快速开始-⭐-核心教程" tabindex="-1"><a href="./getting-started/">1. 快速开始</a> ⭐ 核心教程 <a class="header-anchor" href="#_1-快速开始-⭐-核心教程" aria-label="Permalink to &quot;[1. 快速开始](./getting-started/) ⭐ 核心教程&quot;">​</a></h3><p><strong>学完你能做什么</strong>：</p><ul><li>✅ 在你的设备上安装 Clawdbot</li><li>✅ 配置 AI 模型认证（Anthropic / OpenAI / 其他提供商）</li><li>✅ 启动 Gateway 守护进程</li><li>✅ 通过 WebChat 或配置的渠道发送第一条消息</li></ul><p><strong>适合人群</strong>：所有用户，必读教程</p><p><strong>预计时间</strong>：15-20 分钟</p><p><strong>主要内容</strong>：</p><ul><li>使用 npm/pnpm/bun 安装 Clawdbot</li><li>运行 onboarding 向导完成基础配置</li><li>启动 Gateway 并验证状态</li><li>通过 CLI 或渠道发送测试消息</li></ul><p><strong>前置条件</strong>：无</p><hr><h3 id="_2-向导式配置" tabindex="-1"><a href="./onboarding-wizard/">2. 向导式配置</a> <a class="header-anchor" href="#_2-向导式配置" aria-label="Permalink to &quot;[2. 向导式配置](./onboarding-wizard/)&quot;">​</a></h3><p><strong>学完你能做什么</strong>：</p><ul><li>✅ 使用交互式向导完成完整配置</li><li>✅ 理解 QuickStart 和 Manual 两种模式的区别</li><li>✅ 配置 Gateway 网络、认证和 Tailscale</li><li>✅ 设置 AI 模型提供商（setup-token 和 API Key）</li><li>✅ 启用通信渠道（WhatsApp、Telegram 等）</li><li>✅ 安装和管理技能包</li></ul><p><strong>适合人群</strong>：想要精细配置的用户，了解高级选项</p><p><strong>预计时间</strong>：20-30 分钟</p><p><strong>主要内容</strong>：</p><ul><li>QuickStart vs Manual 模式选择</li><li>Gateway 网络配置（端口、绑定、认证）</li><li>AI 模型认证方式（setup-token 推荐）</li><li>通信渠道配置流程</li><li>技能系统介绍</li></ul><p><strong>前置条件</strong>：<a href="./getting-started/">快速开始</a></p><hr><h3 id="_3-启动-gateway-⭐-核心教程" tabindex="-1"><a href="./gateway-startup/">3. 启动 Gateway</a> ⭐ 核心教程 <a class="header-anchor" href="#_3-启动-gateway-⭐-核心教程" aria-label="Permalink to &quot;[3. 启动 Gateway](./gateway-startup/) ⭐ 核心教程&quot;">​</a></h3><p><strong>学完你能做什么</strong>：</p><ul><li>✅ 使用命令行启动 Gateway 前台进程</li><li>✅ 配置 Gateway 为后台守护进程（macOS LaunchAgent / Linux systemd / Windows Scheduled Task）</li><li>✅ 理解不同绑定模式（loopback / LAN / Tailnet）和认证方式</li><li>✅ 在开发模式和生产模式之间切换</li><li>✅ 使用 <code>--force</code> 强制释放被占用的端口</li></ul><p><strong>适合人群</strong>：所有用户，必读教程</p><p><strong>预计时间</strong>：15-20 分钟</p><p><strong>主要内容</strong>：</p><ul><li>前台模式 vs 守护进程模式</li><li>绑定模式选择（loopback / LAN / Tailnet / Auto）</li><li>认证方式配置（Token / Password / Tailscale Identity）</li><li>开发模式（<code>--dev</code>）和生产模式</li><li>服务管理命令（install / start / stop / restart）</li><li>端口冲突处理（<code>--force</code>）</li></ul><p><strong>前置条件</strong>：<a href="./onboarding-wizard/">向导式配置</a></p><hr><h3 id="_4-发送第一条消息-⭐-核心教程" tabindex="-1"><a href="./first-message/">4. 发送第一条消息</a> ⭐ 核心教程 <a class="header-anchor" href="#_4-发送第一条消息-⭐-核心教程" aria-label="Permalink to &quot;[4. 发送第一条消息](./first-message/) ⭐ 核心教程&quot;">​</a></h3><p><strong>学完你能做什么</strong>：</p><ul><li>✅ 通过 WebChat 界面发送消息</li><li>✅ 通过已配置渠道（WhatsApp / Telegram / Slack 等）与 AI 助手对话</li><li>✅ 理解消息路由和响应流程</li><li>✅ 使用 AI 助手执行基本任务（查询、总结、代码生成等）</li></ul><p><strong>适合人群</strong>：所有用户，必读教程</p><p><strong>预计时间</strong>：10-15 分钟</p><p><strong>主要内容</strong>：</p><ul><li>WebChat 界面使用</li><li>各渠道消息发送方式</li><li>消息格式和回复机制</li><li>常见任务示例（查询信息、生成代码、总结文本）</li><li>调试和故障排查</li></ul><p><strong>前置条件</strong>：<a href="./gateway-startup/">启动 Gateway</a></p><hr><h3 id="_5-dm-配对与访问控制" tabindex="-1"><a href="./pairing-approval/">5. DM 配对与访问控制</a> <a class="header-anchor" href="#_5-dm-配对与访问控制" aria-label="Permalink to &quot;[5. DM 配对与访问控制](./pairing-approval/)&quot;">​</a></h3><p><strong>学完你能做什么</strong>：</p><ul><li>✅ 了解默认的 DM 配对保护机制</li><li>✅ 批准或拒绝陌生发送者的配对请求</li><li>✅ 配置白名单和黑名单</li><li>✅ 设置访问控制策略</li><li>✅ 理解配对模式和安全最佳实践</li></ul><p><strong>适合人群</strong>：关注安全的用户，推荐学习</p><p><strong>预计时间</strong>：10-15 分钟</p><p><strong>主要内容</strong>：</p><ul><li>DM 配对机制原理</li><li>配对流程和用户体验</li><li>白名单和黑名单配置</li><li>访问控制策略设置</li><li>安全最佳实践</li></ul><p><strong>前置条件</strong>：<a href="./first-message/">发送第一条消息</a></p><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-我应该学习所有教程吗" tabindex="-1">Q: 我应该学习所有教程吗？ <a class="header-anchor" href="#q-我应该学习所有教程吗" aria-label="Permalink to &quot;Q: 我应该学习所有教程吗？&quot;">​</a></h3><p><strong>A</strong>: 不一定。如果你想快速上手，只需学习「快速开始」和「启动 Gateway」两个核心教程，然后就可以开始使用 Clawdbot 了。其他教程可以根据需要按需学习。</p><h3 id="q-跳过某些教程会有影响吗" tabindex="-1">Q: 跳过某些教程会有影响吗？ <a class="header-anchor" href="#q-跳过某些教程会有影响吗" aria-label="Permalink to &quot;Q: 跳过某些教程会有影响吗？&quot;">​</a></h3><p><strong>A</strong>: 不会。每个教程都是独立的，但「快速开始」是基础，包含了安装和基本配置，建议首先学习。其他教程可以根据你的需求选择性学习。</p><h3 id="q-我已经熟悉-ai-助手-可以跳过基础教程吗" tabindex="-1">Q: 我已经熟悉 AI 助手，可以跳过基础教程吗？ <a class="header-anchor" href="#q-我已经熟悉-ai-助手-可以跳过基础教程吗" aria-label="Permalink to &quot;Q: 我已经熟悉 AI 助手，可以跳过基础教程吗？&quot;">​</a></h3><p><strong>A</strong>: 可以。如果你已经熟悉类似的 AI 助手工具，可以跳过「快速开始」，直接学习「向导式配置」和「启动 Gateway」来了解 Clawdbot 的特定配置和启动方式。</p><h3 id="q-学习完本章节后-我可以做什么" tabindex="-1">Q: 学习完本章节后，我可以做什么？ <a class="header-anchor" href="#q-学习完本章节后-我可以做什么" aria-label="Permalink to &quot;Q: 学习完本章节后，我可以做什么？&quot;">​</a></h3><p><strong>A</strong>: 完成本章节后，你将拥有一个可以正常使用的 Clawdbot 系统，能够：</p><ul><li>通过 WebChat 或多个渠道与 AI 助手对话</li><li>让 AI 执行基本任务（查询信息、生成代码、总结文本等）</li><li>使用 DM 配对机制保护安全</li><li>继续学习进阶功能（多渠道配置、工具系统、技能平台等）</li></ul><hr><h2 id="下一步指引" tabindex="-1">下一步指引 <a class="header-anchor" href="#下一步指引" aria-label="Permalink to &quot;下一步指引&quot;">​</a></h2><p>完成本章节后，你可以继续学习：</p><ul><li><strong><a href="./../../platforms/channels-overview/">多渠道系统概览</a></strong>：了解 Clawdbot 支持的所有通信渠道及其特点</li><li><strong><a href="./../../platforms/whatsapp/">WhatsApp 渠道</a></strong>：深入学习 WhatsApp 渠道的配置和使用</li><li><strong><a href="./../../platforms/telegram/">Telegram 渠道</a></strong>：深入学习 Telegram 渠道的配置和使用</li><li><strong><a href="./../../platforms/webchat/">WebChat 界面</a></strong>：了解内置的 WebChat 界面功能</li></ul><div class="tip custom-block"><p class="custom-block-title">提示</p><p>根据你的使用需求，选择对应的渠道进行深入学习。如果你主要使用某个渠道（如 WhatsApp 或 Telegram），可以优先学习该渠道的专门教程。</p></div>`,79)])])}const u=l(e,[["render",r]]);export{c as __pageData,u as default};
